const type = $input.first().json.type;

const messages = {
  note_success: {
    success: true,
    texts: [
      "Note added 📝",
      "Saved that for you 💾",
      "Got it. Your note is saved 📝",
      "Your note’s in 📌",
      "Note added ✅"
    ]
  },

  note_list: {
    success: true,
    texts: [
      "Here are your notes 📝",
      "This is what you’ve saved 📚",
      "Your notes, all in one place 👇",
      "Here’s what I found in your notes 📖"
    ]
  },

  note_empty: {
    success: true,
    texts: [
      "No notes yet 📝",
      "Nothing in your notes 📭",
      "You haven’t saved any notes so far 🤔",
      "It’s empty here—no notes found ✨"
    ]
  },

  task_success: {
    success: true,
    texts: [
      "Done. Task added ✅",
      "Your task is on the list 📋",
      "Added it to your tasks 🗂️",
      "All set—that task’s in ✔️"
    ]
  },

  task_list: {
    success: true,
    texts: [
      "Here’s what’s on your list 📋",
      "Your tasks right now 👇",
      "This is what you’ve got lined up 🗂️",
      "Here are your current tasks ✅"
    ]
  },

  task_empty: {
    success: true,
    texts: [
      "Your task list is empty ✨",
      "Nothing on your plate right now 😌",
      "All clear—no tasks yet 🟢",
      "You’re free for now, no tasks found 🎉"
    ]
  },

  command_typo: {
    success: false,
    texts: [
      "That looks close, but not quite right ⚠️ Can you review this command?",
      "I see what you’re going for, but the command’s slightly off 🤏",
      "Hmm, that command looks misspelled 🧐 Give it another try?",
      "Almost there—I think there’s a typo ✏️"
    ]
  },

  unknown_command: {
    success: false,
    texts: [
      "I didn’t quite get that command 🤷‍♂️",
      "I’m not sure what you mean 🤨 Want to review this command?",
      "That command doesn’t ring a bell 🔍"
    ]
  },

  internal_error: {
    success: false,
    texts: [
      "Something didn’t go as expected ⚠️",
      "That didn’t work—something broke internally 🛠️",
      "Something failed on my end ⚠️",
      "That didn’t go through—internal issue ⚠️"
    ]
  },
};

const entry = messages[type] || {
  success: false,
  texts: ["Something went wrong 🤨"]
};

const message = entry.texts[Math.floor(Math.random() * entry.texts.length)];

return {
  json: {
    success: entry.success,
    message
  }
};
